SELECT , pc.category_name AS parent_name, u.user_name AS create_by_name, o.org_name AS org_name, (SELECT COUNT(1) FROM permission_groups pg WHERE pg.category_id = c.id) AS permission_group_count FROM permission_group_categories c LEFT JOIN permission_group_categories pc ON c.parent_id = pc.id LEFT JOIN po_users u ON c.create_by = u.user_id LEFT JOIN po_organization o ON c.org_id = o.org_id
AND c.category_name LIKE CONCAT('%', #{query.categoryName}, '%')
AND c.category_code = #{query.categoryCode}
AND c.parent_id = #{query.parentId}
AND c.status = #{query.status}
AND c.org_id = #{query.orgId}
ORDER BY c.sort_order ASC, c.create_time DESC

